--
-- Table structure for table `orders`
--

DROP TABLE IF EXISTS `orders`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `orders` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL,
  `recipient_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `payment_method` enum('cod','bank','vnpay','momo') COLLATE utf8mb4_unicode_ci DEFAULT 'cod',
  `payment_status` enum('pending','paid','failed','refunded') COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  `payment_ref` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `payment_bank` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `payment_transaction_no` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `paid_at` datetime DEFAULT NULL,
  `note` text COLLATE utf8mb4_unicode_ci,
  `return_reason` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Lý do hoàn hàng của khách',
  `return_evidence` json DEFAULT NULL COMMENT 'Danh sách URL ảnh minh chứng',
  `return_requested_at` datetime DEFAULT NULL,
  `return_approved_at` datetime DEFAULT NULL,
  `return_rejected_at` datetime DEFAULT NULL,
  `return_rejection_reason` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `return_received_at` datetime DEFAULT NULL,
  `hold_expires_at` datetime DEFAULT NULL,
  `recipient_phone` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `total` decimal(10,2) NOT NULL,
  `status` enum('pending','confirmed','shipping','delivered','cancelled','failed_delivery_retry','failed_delivery','return','refund_pending','refund','return_requested','return_approved','return_rejected','return_received') COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  `confirmed_at` timestamp NULL DEFAULT NULL,
  `shipping_at` timestamp NULL DEFAULT NULL,
  `delivered_at` timestamp NULL DEFAULT NULL,
  `failed_delivery_at` timestamp NULL DEFAULT NULL,
  `failed_delivery_final_at` timestamp NULL DEFAULT NULL,
  `return_at` timestamp NULL DEFAULT NULL,
  `refund_pending_at` timestamp NULL DEFAULT NULL,
  `refunded_at` timestamp NULL DEFAULT NULL,
  `cancelled_at` timestamp NULL DEFAULT NULL,
  `retry_count` int DEFAULT '0',
  `shipping_address` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `phone` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `user_address_id` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_status` (`status`),
  KEY `idx_created_at` (`created_at`),
  KEY `fk_orders_user_address` (`user_address_id`),
  CONSTRAINT `fk_orders_user_address` FOREIGN KEY (`user_address_id`) REFERENCES `user_addresses` (`id`),
  CONSTRAINT `orders_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=99 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

